// Generated by OrchestKit M130 — issue #1487
//
// Unit tests for the cc-version-check SessionStart hook. Three branches:
//   - below floor → outputWithNotification (user warning)
//   - above matrix latest → outputPromptContext (claude nudge)
//   - in range → outputSilentSuccess
// Plus: ORK_NO_CC_VERSION_CHECK opt-out + once-per-session rate limit.

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => ''),
  mkdirSync: vi.fn(),
  writeFileSync: vi.fn(),
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { ccVersionCheck } from '../../lifecycle/cc-version-check.js';
import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

function makeInput(sessionId = 'test-session'): HookInput {
  return { tool_name: 'SessionStart', session_id: sessionId, project_dir: '/test/project', tool_input: {} };
}

const ORIG_VERSION_ENV = process.env.CLAUDE_CODE_VERSION;
const ORIG_OPT_OUT = process.env.ORK_NO_CC_VERSION_CHECK;

beforeEach(() => {
  vi.clearAllMocks();
  delete process.env.CLAUDE_CODE_VERSION;
  delete process.env.ORK_NO_CC_VERSION_CHECK;
});

afterEach(() => {
  if (ORIG_VERSION_ENV !== undefined) process.env.CLAUDE_CODE_VERSION = ORIG_VERSION_ENV;
  else delete process.env.CLAUDE_CODE_VERSION;
  if (ORIG_OPT_OUT !== undefined) process.env.ORK_NO_CC_VERSION_CHECK = ORIG_OPT_OUT;
  else delete process.env.ORK_NO_CC_VERSION_CHECK;
});

describe('cc-version-check', () => {
  it('opts out when ORK_NO_CC_VERSION_CHECK=1', () => {
    process.env.ORK_NO_CC_VERSION_CHECK = '1';
    process.env.CLAUDE_CODE_VERSION = '2.1.50'; // even way-below-floor must not warn
    const result = ccVersionCheck(makeInput(), createTestContext());
    expect(result.continue).toBe(true);
    expect(result.systemMessage).toBeUndefined();
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  it('silent success when CLAUDE_CODE_VERSION is unset', () => {
    const result = ccVersionCheck(makeInput(), createTestContext());
    expect(result.continue).toBe(true);
    expect(result.systemMessage).toBeUndefined();
  });

  it('warns user when running CC is below floor', () => {
    process.env.CLAUDE_CODE_VERSION = '2.1.50';
    const result = ccVersionCheck(makeInput('below-test'), createTestContext());
    expect(result.continue).toBe(true);
    expect(result.systemMessage).toContain('2.1.50');
    expect(result.systemMessage).toContain('below');
    expect(result.systemMessage?.toLowerCase()).toContain('floor');
  });

  it('nudges Claude when running CC is above matrix latest', () => {
    process.env.CLAUDE_CODE_VERSION = '2.1.999';
    const result = ccVersionCheck(makeInput('above-test'), createTestContext());
    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('cc-version-check');
    expect(result.hookSpecificOutput?.additionalContext).toContain('2.1.999');
    expect(result.hookSpecificOutput?.additionalContext).toContain('cc-adoption');
  });

  it('silent success when running CC is exactly the matrix latest', () => {
    // Pick a version that exists in the current matrix snapshot and is
    // >= the support floor. Updating both values is required when floor
    // or latest moves: M128 set 2.1.122 floor, M131 set 2.1.125 floor /
    // 2.1.128 latest, 2026-05-07 bolder bump set 2.1.132 floor / latest,
    // M134 W4 closeout (2026-05-10) bumped to 2.1.138 floor / latest,
    // M137 (2026-05-12) bumped to 2.1.139 floor / latest,
    // #1945 (2026-05-24) ladder capstone bumped to 2.1.148 floor / latest.
    // 2026-06-07 owner decision: strict floor=latest=latest_known=2.1.168.
    process.env.CLAUDE_CODE_VERSION = '2.1.168';
    const result = ccVersionCheck(makeInput('in-range-test'), createTestContext());
    expect(result.continue).toBe(true);
    expect(result.systemMessage).toBeUndefined();
    expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
  });

  it('rate-limits to once per session via flag file', () => {
    process.env.CLAUDE_CODE_VERSION = '2.1.50'; // would warn on first call
    const writtenFlags = new Set<string>();
    const efs = vi.mocked(existsSync);
    const wfs = vi.mocked(writeFileSync);

    // Stateful mock: existsSync returns true for any path we've written via writeFileSync.
    // shared/cc-support.json is never written → always false.
    efs.mockImplementation((p) => {
      const path = String(p);
      if (path.endsWith('shared/cc-support.json')) return false;
      if (path.endsWith('.claude/state')) return true;
      return writtenFlags.has(path);
    });
    wfs.mockImplementation((p) => {
      writtenFlags.add(String(p));
    });

    const r1 = ccVersionCheck(makeInput('rate-session'), createTestContext());
    expect(r1.systemMessage).toBeTruthy();

    const r2 = ccVersionCheck(makeInput('rate-session'), createTestContext());
    expect(r2.systemMessage).toBeUndefined();
  });

  it('reads supported_floor from shared/cc-support.json when present', () => {
    process.env.CLAUDE_CODE_VERSION = '2.1.110';
    const efs = vi.mocked(existsSync);
    const rfs = vi.mocked(readFileSync);

    efs.mockImplementation((p) => {
      const path = String(p);
      if (path.endsWith('shared/cc-support.json')) return true;
      if (path.endsWith('.claude/state')) return true;
      return false; // flag file absent
    });
    // readFileSync(path, 'utf8') returns string (not Buffer) — match the production signature.
    rfs.mockReturnValue(JSON.stringify({ supported_floor: '2.1.115', latest: '2.1.120' }));

    const r = ccVersionCheck(makeInput('floor-test'), createTestContext());
    expect(r.systemMessage).toContain('2.1.115');
    expect(r.systemMessage).toContain('2.1.110');
  });
});
